#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class EditController : ControllerBase
    {
        private readonly global::IEditService iEditService;
        public EditController(global::IEditService iEditService)
        {
            this.iEditService = iEditService;
        }
        [Route("ModifyUser/{id}")]
        [HttpPut]
        public string ModifyUser([FromRoute] int id, [FromBody] string name)
        {
            return this.iEditService.ModifyUser(id, name);
        }
    }
}
